(() => {
  const events = [
    {
      full: 'The assassin fired his high-powered rifle from the hotel balcony, striking the president in the chest.',
      mid: 'Someone shot the president → PROPEL(projectile, person)',
      compressed: 'HARM(agent, patient)',
      operator: 'PROPEL → HARM',
      stateChange: 'patient: alive → harmed; agent: hidden → exposed'
    },
    {
      full: 'Mary reached across the oak dining table and handed John the heavy organic chemistry textbook.',
      mid: 'Mary gave John a book → ATRANS(object, source, dest)',
      compressed: 'ATRANS(agent, patient, object)',
      operator: 'ATRANS',
      stateChange: 'Mary: +book → -book; John: -book → +book'
    },
    {
      full: 'The physics teacher stood at the whiteboard and explained the double-slit experiment to 30 confused undergrads.',
      mid: 'Teacher told students about physics → MTRANS(info, source, dest)',
      compressed: 'MTRANS(agent, patient, info)',
      operator: 'MTRANS',
      stateChange: 'students: ¬know(topic) → know(topic)'
    },
    {
      full: 'The experienced neurosurgeon carefully used a laser scalpel to excise the 3cm glioblastoma from the frontal lobe.',
      mid: 'Surgeon removed tumor → MOVE(object) + HARM(tumor)',
      compressed: 'MOVE(agent, object, source)',
      operator: 'MOVE + HARM',
      stateChange: 'patient: has(tumor) → ¬has(tumor)'
    }
  ];
  const e = events[state.selectedEvent || 0];
  const b = state.beta || 1.0;
  let display, label;
  if (b < 0.5) {
    display = e.compressed;
    label = 'Maximum compression — pure operator';
  } else if (b < 1.2) {
    display = e.mid;
    label = 'Balanced — operator + key roles';
  } else {
    display = e.full;
    label = 'Low compression — full description';
  }
  return `β = ${b.toFixed(1)} → ${label}\n\n📝 ${display}\n\n🔧 Operator: ${e.operator}\n📊 State change: ${e.stateChange}\n\n💡 Notice: regardless of β, the OPERATOR stays the same.\nCompression strips surface details, not causal structure.`;
})()

(() => {
  const levels = {
    none: {
      survives: '✅ Operator type (HARM)\n✅ Agent identity (assassin)\n✅ Patient identity (president)\n✅ Instrument (rifle)\n✅ Location (hotel balcony)\n✅ Manner (carefully aimed)\n✅ Time (dawn)',
      bits: '~200 bits',
      insight: 'Everything preserved. No generalization possible.'
    },
    light: {
      survives: '✅ Operator type (HARM)\n✅ Agent identity (assassin)\n✅ Patient identity (president)\n✅ Instrument (rifle)\n❌ Location\n❌ Manner\n❌ Time',
      bits: '~80 bits',
      insight: 'Peripheral details stripped. Core event structure intact.'
    },
    medium: {
      survives: '✅ Operator type (HARM)\n✅ Agent role (human)\n✅ Patient role (human)\n✅ Instrument type (weapon)\n❌ Specific identities\n❌ Location\n❌ Manner',
      bits: '~30 bits',
      insight: 'Abstraction begins! Identities become ROLES. This is where operator structure emerges.'
    },
    heavy: {
      survives: '✅ Operator type (HARM)\n✅ Agent (animate)\n✅ Patient (animate)\n❌ Instrument\n❌ Everything else',
      bits: '~10 bits',
      insight: 'Nearly pure operator. Just the transformation type and role types.'
    },
    extreme: {
      survives: '✅ Operator type (HARM)\n❌ Everything else',
      bits: '~4 bits',
      insight: 'Pure primitive! Just the operator label. This IS the Schankian primitive — the incompressible semantic core.'
    }
  };
  const l = levels[state.compressionLevel || 'medium'];
  return `Compression: ${state.compressionLevel || 'medium'}\n\nWhat survives:\n${l.survives}\n\n📦 Approximate bits needed: ${l.bits}\n\n💡 ${l.insight}`;
})()

(() => {
  const b = state.beta || 1.0;
  const phases = [
    { threshold: 0.3, label: 'Phase 1: Pure operators', desc: 'Only ~14 primitive types survive. This IS the Schankian level.', bits: 4 },
    { threshold: 0.8, label: 'Phase 2: Operators + role types', desc: 'Agent/patient animacy, volitionality emerge as worth encoding.', bits: 12 },
    { threshold: 1.5, label: 'Phase 3: + Instrument/manner', desc: 'HOW the action was performed becomes informative.', bits: 30 },
    { threshold: 2.5, label: 'Phase 4: + Identities/context', desc: 'WHO specifically and WHERE — full reconstruction.', bits: 100 }
  ];
  let current = phases[0];
  for (const p of phases) {
    if (b >= p.threshold) current = p;
  }
  const bar = (bits, max) => '█'.repeat(Math.round(bits / max * 30)) + '░'.repeat(30 - Math.round(bits / max * 30));
  return `β = ${b.toFixed(1)}

🔬 Current phase: ${current.label}
${current.desc}

Information preserved: ~${current.bits} bits
${bar(current.bits, 100)}

— Phase transitions —
β < 0.3  → Phase 1: Pure operators (~4 bits)
β ≈ 0.8  → Phase 2: + Role types (~12 bits)
β ≈ 1.5  → Phase 3: + Instrument/manner (~30 bits)
β > 2.5  → Phase 4: Full detail (~100+ bits)

⚡ Phase transitions are SHARP — a tiny β change
can suddenly make a whole category of information
worth preserving. Just like physical phase transitions!`;
})()
